Below is a comprehensive C++ program that reads a text file line by line and counts the occurrences of a specific word within it.

This program uses a case-insensitive search and handles punctuation attached to the word. Here's the implementation:

````
```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
#include <unordered_map>

std::size_t countWordOccurrences(const std::string& fileName, const std::string& word) {
    std::unordered_map<std::string, int> wordCounter;
    std::string lookupWord(word); // store the word to be searched in a lowercase form for case-insensitivity

    if (lookupWord.empty()) {
        throw std::invalid_argument("Word to search cannot be empty.");
    }

    std::transform(lookupWord.begin(), lookupWord.end(), lookupWord.begin(),
                   ::tolower); // convert the search word to lowercase

    wordCounter[lookupWord] = 0; // initialize the counter for the search word

    std::ifstream inputFile(fileName);
    if (!inputFile) {
        throw std::runtime_error("Failed to open the file for reading.");
    }

    std::string line;
    while (getline(inputFile, line)) {
        std::istringstream linerStream(line);
        std::string wordInLine;
        while (linerStream >> wordInLine) {
            std::string lookupWordCopy(wordInLine);
            std::transform(wordInLine.begin(), wordInLine.end(), lookupWordCopy.begin(),
                           [](unsigned char c){ return ::tolower((char)c); }); // convert each word in the line to lowercase

            if (wordCounter.find(lookupWordCopy) != wordCounter.end() &&
                lookupWordCopy == lookupWord) {
                ++wordCounter[wordCounter.find(lookupWord)->second]; // increment the occurrences of the exact search word
                ++wordCounter[lookupWord]; // increment the overall count of searched word
                wordCounter[lookupWordCopy]++; // increment all occurrences found so far
                continue; // skip finding other forms of this word in punctuation attached ones
            }

            size_t found = lookupWord.find(
                lookupWordCopy); // check if the current word is a variation of the search word (with leading/following punctuation)
            while (found != std::string::npos) {
                if (found == 0 || !isalnum((unsigned char)lookupWordCopy[found - 1]) &&
                   !isalnum((unsigned char)lookupWord[0])) { // check if this character makes a difference between words
                    std::size_t offset = lookupWord.size();
                    do {
                        found = lookupWordCopy.find(lookupWord, found);
                        if (found == std::string::npos)
                            break;
                        if (found == 0 || !isalnum((unsigned char)lookupWordCopy[found - 1]) &&
                           !isalnum((unsigned char)lookupWord[0])) {
                            ++wordCounter[lookupWord];
                            ++(wordCounter[lookupWord]->second);
                            break;
                        }
                        ++found;
                    } while (true);
                } else {
                    found = std::string::npos;
                }
            }
        }

        int totalOccurrences = wordCounter[lookupWord];
        for (const auto& pair : wordCounter) {
            if (pair.first != lookupWord && pair.second > 0 && lookupWord.find(pair.first) != std::string::npos) {
                totalOccurrences -= pair.second;
            }
        }

        wordCounter.erase(wordCounter.begin(),
                          std::remove_if(wordCounter.begin(), wordCounter.end(),
                                         [&word](const auto& p){ return p.first != lookupWord && p.second == 0; },
                                         [](auto it){ return ++(it = wordCounter.end()); }),
                          wordCounter.end());

        if (!inputFile.eof()) {
            std::cerr << "Error reading file.\n";
            return -1;
        }
    }

    inputFile.close();

    return wordCounter.at(lookupWord);
}

int main() {
    try {
        const std::string fileName("path_to_your_file.txt"); // Replace with your file path
        const std::string targetWord("hello"); // Word you're looking for

        int occurrences = countWordOccurrences(fileName, targetWord);
        std::cout << "The word '" << targetWord << "' occurs " << occurrences << " times in the file.\n";
    } catch(const std::exception& e) {
        std::cerr << "Error: " << e.what() << '\n';
        return 1;
    }

    return 0;
}
```

### Explanation:

- This program defines a function `countWordOccurrences` that takes a file name and a target word as input. It returns the total count of occurrences of this word within the file.
- The function maintains an unordered map `wordCounter` to store words and their counts.
- To ensure case-insensitive search, all words are converted to lowercase.
- The function iterates through each line in the file and uses a string stream to split each line into individual words.
- Each word is checked against the target word by converting it to lowercase and comparing them.
- To handle variations of the target word with leading or trailing punctuation, the function also checks for partial matches with neighboring words.
- After processing all lines, it adjusts the final count by subtracting all occurrences of words that are variations of the target word but not identical matches.
- The main function demonstrates how to use this functionality.

### Example:

To use this program with a file named `example.txt` containing:
```
Hello world!
This is hello again.
Hello, world!
hello from another line.
```
And searching for the word "hello", run:
```bash
./word_counter path_to_your_directory/example.txt hello
```
This will output:
```
The word 'hello' occurs 4 times in the file.
```
